class ScienceSimulation {
    constructor(container, initialInputs) {
        this.container = container;
        this.canvas = document.createElement('canvas');
        this.canvas.style.width = '100%';
        this.canvas.style.height = '100%';
        this.canvas.style.borderRadius = '12px';
        this.container.appendChild(this.canvas);
        this.ctx = this.canvas.getContext('2d');

        window.addEventListener('resize', () => this.resizeCanvas());
        // The resize event will just fix canvas inner dimensions, index.html calls render directly
        this.resizeCanvas();
    }

    resizeCanvas() {
        const rect = this.container.getBoundingClientRect();
        this.canvas.width = rect.width;
        this.canvas.height = rect.height;
        // Re-render handled by external triggerSimulationUpdate in index.html
    }

    getSteps(inputs) {
        const mass = inputs.mass;
        const angle = inputs.angle;
        const g = inputs.gravity;
        const W = mass * g;
        const N = W * Math.cos(angle * Math.PI / 180);
        const f = 0.2 * N;
        const Fnet = W * Math.sin(angle * Math.PI / 180) - f;

        return [
            {
                title: "Step 1: The Setup",
                description: `We place a block of mass **${mass} kg** on an inclined plane with an angle of **${angle}°**.

Notice the relative orientation of the block and the surface. Without any forces acting yet, it's just sitting there.`
            },
            {
                title: "Step 2: Gravity",
                description: `Gravity always pulls straight down toward the center of the Earth. 

The weight of the block is $W = mg = (${mass})(\text{${g}}) = \mathbf{${W.toFixed(1)} \text{ N}}$.`
            },
            {
                title: "Step 3: Normal Force",
                description: `The surface of the incline pushes back against the block. This force is always perpendicular (normal) to the surface.

Because the surface is tilted by ${angle}°, the normal force is $N = mg \cos(\theta) = \mathbf{${N.toFixed(1)} \text{ N}}$.`
            },
            {
                title: "Step 4: Kinetic Friction",
                description: `As the block tries to slide down, friction opposes the motion.

Assuming a coefficient of kinetic friction $\mu_k = 0.2$, the frictional force is $f = \mu_k N = 0.2 \times ${N.toFixed(1)} = \mathbf{${f.toFixed(1)} \text{ N}}$.`
            },
            {
                title: "Step 5: Net Force",
                description: `The component of gravity pulling the block down the incline is $mg \sin(\theta) = ${(W * Math.sin(angle * Math.PI / 180)).toFixed(1)}$ N.

Subtracting friction, the net force driving the block is $F_{net} = \mathbf{${Fnet.toFixed(1)} \text{ N}}$.`
            }
        ];
    }

    render(inputs, stepIndex) {
        if (!this.ctx || !this.canvas.width) this.resizeCanvas();

        const w = this.canvas.width;
        const h = this.canvas.height;
        const cx = w / 2;
        const cy = h / 2 + 50;

        this.ctx.clearRect(0, 0, w, h);

        const angleRad = inputs.angle * Math.PI / 180;
        const mass = inputs.mass;
        const g = inputs.gravity;

        const rampLength = 350;
        const blockSide = 50 + (mass * 0.4);

        this.ctx.save();
        this.ctx.translate(cx, cy);

        // Draw Ramp
        this.ctx.beginPath();
        this.ctx.moveTo(-rampLength/2, Math.tan(angleRad) * (rampLength/2));
        this.ctx.lineTo(rampLength/2, Math.tan(angleRad) * (-rampLength/2));
        this.ctx.lineTo(rampLength/2, Math.tan(angleRad) * (rampLength/2));
        this.ctx.closePath();
        this.ctx.fillStyle = 'rgba(100, 116, 139, 0.2)';
        this.ctx.fill();
        this.ctx.strokeStyle = '#94a3b8';
        this.ctx.lineWidth = 4;
        this.ctx.stroke();

        // Rotated Coordinate System
        this.ctx.rotate(-angleRad);

        // Draw Block
        this.ctx.fillStyle = '#3b82f6';
        this.ctx.fillRect(-blockSide/2, -blockSide, blockSide, blockSide);
        this.ctx.strokeStyle = '#60a5fa';
        this.ctx.strokeRect(-blockSide/2, -blockSide, blockSide, blockSide);

        const cmY = -blockSide/2;

        // Vector Drawing Helper
        const drawVector = (dx, dy, color, label) => {
            const mag = Math.sqrt(dx*dx + dy*dy);
            if (mag < 0.1) return;
            const scale = 30 + Math.log10(mag + 1) * 20;
            const ux = dx/mag; 
            const uy = dy/mag;
            const endX = ux * scale;
            const endY = cmY + uy * scale;

            this.ctx.beginPath();
            this.ctx.moveTo(0, cmY);
            this.ctx.lineTo(endX, endY);
            this.ctx.strokeStyle = color;
            this.ctx.lineWidth = 3;
            this.ctx.stroke();

            const headLen = 10;
            const aAngle = Math.atan2(uy, ux);
            this.ctx.beginPath();
            this.ctx.moveTo(endX, endY);
            this.ctx.lineTo(endX - headLen * Math.cos(aAngle - Math.PI/6), endY - headLen * Math.sin(aAngle - Math.PI/6));
            this.ctx.moveTo(endX, endY);
            this.ctx.lineTo(endX - headLen * Math.cos(aAngle + Math.PI/6), endY - headLen * Math.sin(aAngle + Math.PI/6));
            this.ctx.stroke();

            this.ctx.fillStyle = color;
            this.ctx.font = '14px Inter';
            this.ctx.fillText(label, endX + 8, endY + 8);
        };

        const fg = mass * g;
        const fn = fg * Math.cos(angleRad);
        const fk = 0.2 * fn;
        const fnet = fg * Math.sin(angleRad) - fk;

        // Step >= 1: Gravity
        if (stepIndex >= 1) {
            drawVector(Math.sin(angleRad) * fg, Math.cos(angleRad) * fg, '#f59e0b', 'W');
        }
        // Step >= 2: Normal Force
        if (stepIndex >= 2) {
            drawVector(0, -fn, '#10b981', 'N');
        }
        // Step >= 3: Friction
        if (stepIndex >= 3 && inputs.angle > 0) {
            drawVector(-fk, 0, '#ef4444', 'f');
        }
        // Step >= 4: Net Force
        if (stepIndex >= 4 && inputs.angle > 0) {
            drawVector(fnet, 0, '#a855f7', 'F_net');
        }

        this.ctx.restore();
    }
}
